// Flutter imports:
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:flutter/material.dart';

// Package imports:
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/member_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/subscription_controller.dart';
import 'package:baseball_detector_flutter/controllers/team_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/user_accessible_contents_controller.dart';
import 'package:baseball_detector_flutter/controllers/user_info_controller.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/result.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/utils/build_context_ext.dart';
import 'package:baseball_detector_flutter/utils/environment.dart';
import 'package:baseball_detector_flutter/views/components/custom_loading_indicator.dart';
import 'package:baseball_detector_flutter/views/pages/home/home_page.dart';
import 'package:baseball_detector_flutter/views/pages/home/settings/components/debug_card.dart';
import 'package:baseball_detector_flutter/views/pages/home/settings/components/delete_account_button.dart';
import 'package:baseball_detector_flutter/views/pages/home/settings/components/legal_and_support_card.dart';
import 'package:baseball_detector_flutter/views/pages/home/settings/components/plan_card.dart';
import 'package:baseball_detector_flutter/views/pages/home/settings/components/preferences_card.dart';
import 'package:baseball_detector_flutter/views/pages/home/settings/components/profile_card.dart';
import 'package:baseball_detector_flutter/views/pages/home/settings/components/section_header.dart';
import 'package:baseball_detector_flutter/views/pages/home/settings/components/sign_out_button.dart';
import 'package:baseball_detector_flutter/views/pages/home/settings/super_admin_team_switcher/super_admin_team_switcher_page.dart';
import 'package:baseball_detector_flutter/views/themes/font_manager.dart';

class SettingsPage extends HookConsumerWidget {
  const SettingsPage({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final userInfoState = ref.watch(userInfoControllerProvider);
    final teamListState = ref.watch(teamListControllerProvider);
    final currentTeamId = ref.watch(profileStorageProvider).getTeamId();

    return Scaffold(
      body: Padding(
        padding: HomePage.bodyPadding,
        child: RefreshIndicator(
          onRefresh: () async {
            ref
              ..invalidate(userInfoControllerProvider)
              ..invalidate(memberListControllerProvider)
              ..invalidate(teamListControllerProvider)
              ..read(subscriptionControllerProvider.notifier)
                  .updateCurrentEntitlement();

            // Refresh user's accessible contents to get latest role permissions
            await ref
                .read(userAccessibleContentsControllerProvider.notifier)
                .refresh();
          },
          child: teamListState.fold(
            loading: () => CustomLoadingIndicator(),
            error: (error) => _buildErrorWidget(context, error),
            data: (teamList) => userInfoState.fold(
              loading: () => CustomLoadingIndicator(),
              error: (error) => _buildErrorWidget(context, error),
              data: (userInfo) => SafeArea(
                child: SingleChildScrollView(
                  child: Column(
                    children: [
                      if (context.isLandscape) const Gap(16),
                      SectionHeader(
                        title: context.l10n.settings_page__account_header,
                        icon: Icons.person_outline,
                      ),
                      const Gap(8),
                      ProfileCard(userInfo: userInfo),
                      const Gap(24),
                      SectionHeader(
                        title: context.l10n.settings_page__plan_header,
                        icon: Icons.workspace_premium_outlined,
                      ),
                      const Gap(8),
                      PlanCard(teamList: teamList),
                      const Gap(24),
                      if (isDev || isStg) ...[
                        SectionHeader(
                          title: 'Debug',
                          icon: Icons.bug_report_outlined,
                        ),
                        const Gap(8),
                        const DebugCard(),
                        const Gap(24),
                      ],
                      SectionHeader(
                        title: context.l10n.settings_page__app_settings_header,
                        icon: Icons.tune_outlined,
                      ),
                      const Gap(8),
                      PreferencesCard(teamList: teamList, userInfo: userInfo),
                      const Gap(24),
                      if (userInfo.isSuperAdmin || userInfo.isSuperReader) ...[
                        SectionHeader(
                          title: context
                              .l10n.super_admin_team_switcher__section_title,
                          icon: Icons.admin_panel_settings_outlined,
                        ),
                        const Gap(8),
                        Card(
                          child: Column(
                            children: [
                              ListTile(
                                leading: const Icon(Icons.business),
                                title: Text(
                                  context.l10n
                                      .super_admin_team_switcher__current_team,
                                ),
                                subtitle: Text(
                                  teamList
                                          .firstWhere(
                                            (team) => team.id == currentTeamId,
                                            orElse: () => teamList.first,
                                          )
                                          .name ??
                                      context.l10n.no_team_name,
                                  style: TextStyleManager.body1.copyWith(
                                    fontWeight: FontWeight.bold,
                                  ),
                                ),
                              ),
                              const Divider(height: 1),
                              ListTile(
                                leading: const Icon(Icons.swap_horiz),
                                title: Text(
                                  context.l10n.super_admin_team_switcher__title,
                                ),
                                subtitle: Text(
                                  context.l10n
                                      .super_admin_team_switcher__description,
                                ),
                                trailing: const Icon(Icons.chevron_right),
                                onTap: () {
                                  Navigator.of(context).push(
                                    MaterialPageRoute(
                                      builder: (context) =>
                                          const SuperAdminTeamSwitcherPage(),
                                    ),
                                  );
                                },
                              ),
                            ],
                          ),
                        ),
                        const Gap(24),
                      ],
                      SectionHeader(
                        title: context
                            .l10n.settings_page__legal_and_support_header,
                        icon: Icons.info_outline,
                      ),
                      const Gap(8),
                      LegalAndSupportCard(userInfo: userInfo),
                      const Gap(24),
                      const SignOutButton(),
                      const Gap(24),
                      if (userInfo.isOnlyBelongingToSingleTeam())
                        DeleteAccountButton(),
                      const Gap(24),
                    ],
                  ),
                ),
              ),
            ),
          ),
        ),
      ),
    );
  }

  Widget _buildErrorWidget(BuildContext context, Failure error) => Card(
        child: Padding(
          padding: const EdgeInsets.symmetric(horizontal: 20, vertical: 16),
          child: Row(
            mainAxisAlignment: MainAxisAlignment.center,
            children: [
              Icon(
                Icons.error_outline,
                size: 24,
                color: Theme.of(context).colorScheme.error,
              ),
              const Gap(16),
              Column(
                mainAxisAlignment: MainAxisAlignment.center,
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(
                    context.l10n.get_data_failed,
                    style: TextStyleManager.body1.copyWith(
                      color: Theme.of(context).colorScheme.error,
                    ),
                  ),
                  Text(
                    error.translate(context.l10n),
                    style: TextStyleManager.body1.copyWith(
                      color: Theme.of(context).colorScheme.error,
                    ),
                  ),
                ],
              ),
            ],
          ),
        ),
      );
}

