@riverpod
class CurrentTeamController extends _$CurrentTeamController {
  @override
  Future<Team?> build() async {
    final currentTeamId = ref.watch(profileStorageProvider).getTeamId();
    if (currentTeamId == null) return null;

    final repository = ref.watch(repositoryProvider);

    // Try to get from searchTeams API
    final result = await repository.searchTeams(
      page: 0,
      pageSize: 1,
    );

    return result.fold(
      (failure) => null,
      (response) {
        // Find the team with current team ID
        return response.teams.firstWhere(
          (team) => team.id == currentTeamId,
          orElse: () => response.teams.isNotEmpty ? response.teams.first : null,
        );
      },
    );
  }

  Future<void> refresh() async {
    ref.invalidateSelf();
    await future;
  }
}

