   109→  ResourceData _reprocessResourceWithBallInfo(
   110→    ResourceData resource,
   111→    String teamId,
   112→    String sessionId,
   113→    String? userId,
   114→  ) {
   115→    final ballInfoList = resource.ballInfoList!.toList()
   116→      ..retainWhere((ballInfo) =>
   117→          (ballInfo.ball.isPitched ?? false) || (ballInfo.ball.isHit ?? false));
   118→
   119→    return _reprocessResource(
   120→      resource.copyWith(ballInfoList: ballInfoList),
   121→      teamId,
   122→      sessionId,
   123→      userId,
   124→    );
   125→  }
