import 'package:baseball_detector_flutter/views/themes/font_manager.dart';

class SettingsPage extends HookConsumerWidget {
  const SettingsPage({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final userInfoState = ref.watch(userInfoControllerProvider);
    final teamListState = ref.watch(teamListControllerProvider);
    final currentTeamState = ref.watch(currentTeamControllerProvider);

    return Scaffold(
      body: Padding(
        padding: HomePage.bodyPadding,
        child: RefreshIndicator(
          onRefresh: () async {
            ref
              ..invalidate(userInfoControllerProvider)
              ..invalidate(memberListControllerProvider)
              ..invalidate(teamListControllerProvider)
              ..invalidate(currentTeamControllerProvider)
              ..read(subscriptionControllerProvider.notifier)
                  .updateCurrentEntitlement();

            // Refresh user's accessible contents to get latest role permissions
            await ref
                .read(userAccessibleContentsControllerProvider.notifier)
                .refresh();
          },
          child: teamListState.fold(
            loading: () => CustomLoadingIndicator(),
            error: (error) => _buildErrorWidget(context, error),
            data: (teamList) => userInfoState.fold(
              loading: () => CustomLoadingIndicator(),
              error: (error) => _buildErrorWidget(context, error),
              data: (userInfo) => SafeArea(
                child: SingleChildScrollView(
                  child: Column(
                    children: [
                      if (context.isLandscape) const Gap(16),
                      SectionHeader(
                        title: context.l10n.settings_page__account_header,
                        icon: Icons.person_outline,
                      ),
                      const Gap(8),
                      ProfileCard(userInfo: userInfo),
                      const Gap(24),
                      SectionHeader(
                        title: context.l10n.settings_page__plan_header,
                        icon: Icons.workspace_premium_outlined,
                      ),
                      const Gap(8),
                      PlanCard(teamList: teamList),
                      const Gap(24),
                      if (isDev || isStg) ...[
                        SectionHeader(
                          title: 'Debug',
                          icon: Icons.bug_report_outlined,
                        ),
                        const Gap(8),
                        const DebugCard(),
                        const Gap(24),
                      ],
                      SectionHeader(
                        title: context.l10n.settings_page__app_settings_header,
                        icon: Icons.tune_outlined,
                      ),
                      const Gap(8),
                      PreferencesCard(teamList: teamList, userInfo: userInfo),
                      const Gap(24),
                      if (userInfo.isSuperAdmin || userInfo.isSuperReader) ...[
                        SectionHeader(
                          title: context
                              .l10n.super_admin_team_switcher__section_title,
                          icon: Icons.admin_panel_settings_outlined,
                        ),
                        const Gap(8),
                        currentTeamState.fold(
                          loading: () => Card(
                            child: ListTile(
                              leading: const Icon(Icons.business),
                              title: Text(
                                context.l10n
                                    .super_admin_team_switcher__current_team,
                              ),
                              subtitle: CustomLoadingIndicator(),
                            ),
                          ),
                          error: (error) => Card(
                            child: ListTile(
                              leading: Icon(
                                Icons.error_outline,
                                color: Theme.of(context).colorScheme.error,
                              ),
                              title: Text(
                                context.l10n
                                    .super_admin_team_switcher__current_team,
                              ),
                              subtitle: Text(
                                error.translate(context.l10n),
                                style: TextStyleManager.body1.copyWith(
                                  color: Theme.of(context).colorScheme.error,
                                ),
                              ),
                            ),
                          ),
                          data: (teamResult) => teamResult.fold(
                            (failure) => Card(
                              child: ListTile(
                                leading: Icon(
                                  Icons.error_outline,
                                  color: Theme.of(context).colorScheme.error,
                                ),
                                title: Text(
                                  context.l10n
                                      .super_admin_team_switcher__current_team,
                                ),
                                subtitle: Text(
                                  failure.translate(context.l10n),
                                  style: TextStyleManager.body1.copyWith(
                                    color: Theme.of(context).colorScheme.error,
                                  ),
                                ),
                              ),
                            ),
                            (team) => Card(
                              child: Column(
                                children: [
                                  ListTile(
                                    leading: const Icon(Icons.business),
                                    title: Text(
                                      context.l10n
                                          .super_admin_team_switcher__current_team,
                                    ),
                                    subtitle: Text(
                                      team.name,
                                      style: TextStyleManager.body1.copyWith(
                                        fontWeight: FontWeight.bold,
                                      ),
                                    ),
                                  ),
                                  const Divider(height: 1),
                                  ListTile(
                                    leading: const Icon(Icons.swap_horiz),
                                    title: Text(
                                      context.l10n.super_admin_team_switcher__title,
                                    ),
                                    subtitle: Text(
                                      context.l10n
                                          .super_admin_team_switcher__description,
                                    ),
                                    trailing: const Icon(Icons.chevron_right),
                                    onTap: () {
                                      Navigator.of(context).push(
                                        MaterialPageRoute(
                                          builder: (context) =>
                                              const SuperAdminTeamSwitcherPage(),
                                        ),
                                      );
                                    },
                                  ),
                                ],
                              ),
                            ),
                          ),
                        ),
                        const Gap(24),
                      ],
                      SectionHeader(
                        title: context
                            .l10n.settings_page__legal_and_support_header,
                        icon: Icons.info_outline,
                      ),
                      const Gap(8),
                      LegalAndSupportCard(userInfo: userInfo),
                      const Gap(24),
                      const SignOutButton(),
                      const Gap(24),
                      if (userInfo.isOnlyBelongingToSingleTeam())
                        DeleteAccountButton(),
                      const Gap(24),
                    ],
                  ),
                ),
              ),
            ),
          ),
        ),
      ),
    );
  }

  Widget _buildErrorWidget(BuildContext context, Failure error) => Card(
        child: Padding(
          padding: const EdgeInsets.symmetric(horizontal: 20, vertical: 16),
          child: Row(
            mainAxisAlignment: MainAxisAlignment.center,
            children: [
              Icon(
                Icons.error_outline,
                size: 24,
                color: Theme.of(context).colorScheme.error,
              ),
              const Gap(16),
              Column(
                mainAxisAlignment: MainAxisAlignment.center,
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(
                    context.l10n.get_data_failed,
                    style: TextStyleManager.body1.copyWith(
                      color: Theme.of(context).colorScheme.error,
                    ),
                  ),
                  Text(
                    error.translate(context.l10n),
                    style: TextStyleManager.body1.copyWith(
                      color: Theme.of(context).colorScheme.error,
                    ),
                  ),
                ],
              ),
            ],
          ),
        ),
      );
}

