// Package imports:
import 'package:riverpod_annotation/riverpod_annotation.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/models/team.dart';
import 'package:baseball_detector_flutter/data/result.dart';
import 'package:baseball_detector_flutter/providers/repository_provider.dart';

part 'super_admin_current_team_controller.g.dart';

@riverpod
class SuperAdminCurrentTeamController
    extends _$SuperAdminCurrentTeamController {
  @override
  Future<Result<Failure, Team?>> build(String teamId) async {
    final repository = ref.watch(repositoryProvider);
    final searchResult = await repository.searchTeams(
      keyword: teamId,
      page: 0,
      pageSize: 1,
    );

    return searchResult.fold(
      (failure) => Left(failure),
      (response) {
        if (response.teams.isEmpty) {
          return const Right(null);
        }
        // teamId で完全一致するチームを探す
        final matchedTeam = response.teams.firstWhere(
          (team) => team.id == teamId,
          orElse: () => response.teams.first,
        );
        return Right(matchedTeam);
      },
    );
  }

  Future<void> refresh() async {
    state = const AsyncLoading();
    state = await AsyncValue.guard(() async {
      final repository = ref.read(repositoryProvider);
      final searchResult = await repository.searchTeams(
        keyword: teamId,
        page: 0,
        pageSize: 1,
      );

      return searchResult.fold(
        (failure) => Left(failure),
        (response) {
          if (response.teams.isEmpty) {
            return const Right(null);
          }
          final matchedTeam = response.teams.firstWhere(
            (team) => team.id == teamId,
            orElse: () => response.teams.first,
          );
          return Right(matchedTeam);
        },
      );
    });
  }
}

