class _SuperAdminCurrentTeamCard extends HookConsumerWidget {
  const _SuperAdminCurrentTeamCard({required this.teamId});

  final String teamId;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    if (teamId.isEmpty) {
      return Card(
        child: ListTile(
          leading: Icon(
            Icons.error_outline,
            color: Theme.of(context).colorScheme.error,
          ),
          title: Text(
            context.l10n.super_admin_team_switcher__current_team,
          ),
          subtitle: Text(
            context.l10n.no_team_name,
            style: TextStyleManager.body1.copyWith(
              color: Theme.of(context).colorScheme.error,
            ),
          ),
        ),
      );
    }

    final currentTeamState =
        ref.watch(superAdminCurrentTeamControllerProvider(teamId));

    return currentTeamState.when(
      loading: () => Card(
        child: ListTile(
          leading: const Icon(Icons.business),
          title: Text(
            context.l10n.super_admin_team_switcher__current_team,
          ),
          subtitle: CustomLoadingIndicator(),
        ),
      ),
      error: (error, stack) => Card(
        child: ListTile(
          leading: Icon(
            Icons.error_outline,
            color: Theme.of(context).colorScheme.error,
          ),
          title: Text(
            context.l10n.super_admin_team_switcher__current_team,
          ),
          subtitle: Text(
            error.toString(),
            style: TextStyleManager.body1.copyWith(
              color: Theme.of(context).colorScheme.error,
            ),
          ),
        ),
      ),
      data: (teamResult) => teamResult.fold(
        (failure) => Card(
          child: ListTile(
            leading: Icon(
              Icons.error_outline,
              color: Theme.of(context).colorScheme.error,
            ),
            title: Text(
              context.l10n.super_admin_team_switcher__current_team,
            ),
            subtitle: Text(
              failure.translate(context.l10n),
              style: TextStyleManager.body1.copyWith(
                color: Theme.of(context).colorScheme.error,
              ),
            ),
          ),
        ),
        (team) {
          if (team == null) {
            return Card(
              child: ListTile(
                leading: Icon(
                  Icons.error_outline,
                  color: Theme.of(context).colorScheme.error,
                ),
                title: Text(
                  context.l10n.super_admin_team_switcher__current_team,
                ),
                subtitle: Text(
                  context.l10n.no_team_name,
                  style: TextStyleManager.body1.copyWith(
                    color: Theme.of(context).colorScheme.error,
                  ),
                ),
              ),
            );
          }

          return Card(
            child: Column(
              children: [
                ListTile(
                  leading: const Icon(Icons.business),
                  title: Text(
                    context.l10n.super_admin_team_switcher__current_team,
                  ),
                  subtitle: Text(
                    team.name ?? context.l10n.no_team_name,
                    style: TextStyleManager.body1.copyWith(
                      fontWeight: FontWeight.bold,
                    ),
                  ),
                ),
                const Divider(height: 1),
                ListTile(
                  leading: const Icon(Icons.swap_horiz),
                  title: Text(
                    context.l10n.super_admin_team_switcher__title,
                  ),
                  subtitle: Text(
                    context.l10n.super_admin_team_switcher__description,
                  ),
                  trailing: const Icon(Icons.chevron_right),
                  onTap: () {
                    Navigator.of(context).push(
                      MaterialPageRoute(
                        builder: (context) =>
                            const SuperAdminTeamSwitcherPage(),
                      ),
                    );
                  },
                ),
              ],
            ),
          );
        },
      ),
    );
  }
}

